{
    ConnectionError = "Database connection failed: {0}",
    TransactionStarted = "New transaction initiated"
};

var db = new PostgreHelper(
    connectionString: "Host=localhost;Database=mydb",
    messages: customMessages
);

// Messages will be used in operations
