    {
        ["name"] = "John Doe",
        ["age"] = 30,
        ["scores"] = new JArray { 1, 2, 3 }
    }
};

// Safe property access
string name = json.PropGet<string>(path: "user.name", defaultValue: "Unknown");

// Deep merge
var other = new JObject { ["user"] = new JObject { ["email"] = "john@example.com" } };
var merged = json.PropMerge(other: other);



> [!NOTE]
> All methods are designed to be null-safe and handle edge cases gracefully

> [!TIP]
