This class contains pre-compiled regular expressions for validating: - Email addresses - Numbers (integers, decimals, currency, percentages) - Dates and times - Web-related strings (URLs, IP addresses, domains) - HTML tags - Security-related patterns (passwords, JWT tokens) - Base64 strings - File paths
Example usage:
// Validate email bool isValidEmail = RegexPatternCollections.EmailValidation().IsMatch("user@example.com");
// Validate strong password bool isStrongPassword = RegexPatternCollections.StrongPasswordValidation().IsMatch("P@ssw0rd123");

Extracts characters that: - Are alphanumeric (A-Z, a-z, 0-9) - Match any of the specified special characters
Example usage:
var regex = RegexPatternCollections.AlphanumericFinder(new[] { '@', '_', '-' });
// Valid matches bool isValid1 = regex.IsMatch("user@domain"); // true bool isValid2 = regex.IsMatch("user_name"); // true bool isValid3 = regex.IsMatch("my-string"); // true
// Invalid matches bool isValid4 = regex.IsMatch("user#name"); // false (# not in allowed chars) bool isValid5 = regex.IsMatch("string!"); // false (! not in allowed chars)

Called by  and the finalizer to free resources.


using var logger = new SystemLogging(logDirectory: "logs", source: "MyApp");
logger.Log(message: "Hello world", level: LogLevel.Information);

This method is called before any operation that requires an active settings collection.

Example usage:

private void SomeOperation()
{
    try
    {
        ThrowIfDisposed();
        // Proceed with operation
    }
    catch (ObjectDisposedException ex)
    {
        _logging?.LogError(
            message: "Operation attempted on disposed instance",
            exception: ex
        );
        throw;
    }
}

A collection of utility methods for validating strings in various formats including: - URLs - Email addresses - IP addresses (IPv4 and IPv6) - Phone numbers - Dates - Alphanumeric strings - Pattern matching - Numeric strings
Example usage:
string email = "user@example.com"; bool isValid = email.IsValidEmail();
string url = "https://example.com"; bool isValidUrl = url.IsValidUrl();

example.code:
// Validate an email address
string email = "user@example.com";
if (email.IsValidEmail())
{
    // Process valid email
}

// Validate a URL
string url = "https://example.com";
if (url.IsValidUrl())
{
    // Process valid URL
}

string text = "Hello";
bool isValid = text.HasValidLength(minLength: 3, maxLength: 10); // returns true

string longText = "ThisIsAVeryLongText";
bool isInvalid = longText.HasValidLength(minLength: 3, maxLength: 10); // returns false

string text = "ABC123";
bool isValid = text.IsAlphanumeric(); // returns true

string invalidText = "ABC-123";
bool isInvalid = invalidText.IsAlphanumeric(); // returns false

string number = "12345";
bool isValid = number.IsNumeric(); // returns true

string invalidNumber = "123.45";
bool isInvalid = invalidNumber.IsNumeric(); // returns false

string date = "2024-03-02";
bool isValid = date.IsValidDate(format: "yyyy-MM-dd"); // returns true

string invalidDate = "2024-13-45";
bool isInvalid = invalidDate.IsValidDate(format: "yyyy-MM-dd"); // returns false

string email = "user@example.com";
bool isValid = email.IsValidEmail(); // returns true

string invalidEmail = "not.an.email";
bool isInvalid = invalidEmail.IsValidEmail(); // returns false

string ip = "192.168.1.1";
bool isValid = ip.IsValidIPv4(); // returns true

string invalidIp = "256.1.2.3";
bool isInvalid = invalidIp.IsValidIPv4(); // returns false

string ip = "2001:0db8:85a3:0000:0000:8a2e:0370:7334";
bool isValid = ip.IsValidIPv6(); // returns true

string invalidIp = "256.1.2.3";
bool isInvalid = invalidIp.IsValidIPv6(); // returns false

string phone = "+1-234-567-8900";
bool isValid = phone.IsValidPhoneNumber(); // returns true

string invalidPhone = "123-ABC-4567";
bool isInvalid = invalidPhone.IsValidPhoneNumber(); // returns false

string url = "https://example.com";
bool isValid = url.IsValidUrl(); // returns true

string invalidUrl = "ftp://example.com";
bool isInvalid = invalidUrl.IsValidUrl(); // returns false

string text = "ABC-123";
bool isValid = text.MatchesPattern(pattern: @"^[A-Z]+-\d+$"); // returns true

string invalidText = "abc-123";
bool isInvalid = invalidText.MatchesPattern(pattern: @"^[A-Z]+-\d+$"); // returns false
